useEffect(() => {
  const initLanguage = async () => {
    try {
      const preferences = await invoke<{ language?: string }>('load_preferences')
      await initializeLanguage(preferences.language ?? 'system')
    } catch (error) {
      console.warn('Failed to load preferences for language:', error)
      await initializeLanguage('system')
    }
  }
  initLanguage()
}, [])
